/// Saga 19 step 001: evaluate `llm_call(url, prompt,
/// model)` arguments to strings and delegate the
/// HTTP path to `mlpl_runtime::call_ollama`. The
/// runtime helper owns the URL normalization + JSON
/// parsing; this shim is just the `Expr` -> `String`
/// adapter and the `RuntimeError` -> `EvalError`
/// lift.
fn dispatch_llm_call(
    args: &[Expr],
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<Value, EvalError> {
    if args.len() != 3 {
        return Err(EvalError::BadArity {
            func: "llm_call".into(),
            expected: 3,
            got: args.len(),
        });
    }
    let url = eval_string_arg(&args[0], env, trace)?;
    let prompt = eval_string_arg(&args[1], env, trace)?;
    let model = eval_string_arg(&args[2], env, trace)?;
    let reply = mlpl_runtime::call_ollama(&url, &prompt, &model)
        .map_err(|e| EvalError::Unsupported(format!("{e}")))?;
    Ok(Value::Str(reply))
}

fn eval_string_arg(
    expr: &Expr,
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<String, EvalError> {
    match eval_expr(expr, env, trace)? {
        Value::Str(s) => Ok(s),
        _ => Err(EvalError::ExpectedString),
    }
}

